            href="#contacto"
            className="bg-accent text-black px-6 py-2 rounded-md font-bold text-sm hover:scale-105 transition-transform active:scale-95 shadow-[0_0_15px_rgba(255,224,0,0.3)]"
          >
            COTIZAR
          </a>
        </div>

        {/* Mobile Menu Icon (Placeholder for simplicity) */}
