import React, { useState } from 'react';
import { ContactFormData } from '../types';

const ContactForm: React.FC = () => {
  const [formData, setFormData] = useState<ContactFormData>({
    name: '',
    email: '',
    storeUrl: '',
    message: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // TODO: Connect Firebase Firestore logic here
    console.log('Form submission payload:', formData);

    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setSubmitted(true);
      setFormData({ name: '', email: '', storeUrl: '', message: '' });
    }, 1500);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <section id="contacto" className="py-24 bg-black border-t border-white/5">
      <div className="container mx-auto px-6 max-w-4xl">
        <div className="text-center mb-16">
          <h2 className="text-5xl md:text-7xl font-heavy mb-6">
            HABLEMOS <span className="text-accent">NEGOCIO.</span>
          </h2>
          <p className="text-xl text-gray-400 font-medium">
            Cuéntanos sobre tu proyecto y descubre cómo podemos ayudarte a escalar.
          </p>
        </div>

        {submitted ? (
          <div className="bg-accent/10 border border-accent p-12 rounded-md text-center">
            <h3 className="text-3xl font-heavy text-accent mb-4">¡RECIBIDO!</h3>
            <p className="text-white font-medium">Nos pondremos en contacto contigo en menos de 24 horas.</p>
            <button
              onClick={() => setSubmitted(false)}
              className="mt-8 text-sm font-bold underline hover:text-accent"
            >
              Enviar otro mensaje
            </button>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col space-y-2">
                <label htmlFor="name" className="text-xs font-bold text-gray-500 uppercase tracking-widest">Nombre completo</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="John Doe"
                  className="bg-zinc-900 border-none p-4 rounded-md text-white focus:ring-2 focus:ring-accent outline-none transition-all"
                />
              </div>
              <div className="flex flex-col space-y-2">
                <label htmlFor="email" className="text-xs font-bold text-gray-500 uppercase tracking-widest">Email Corporativo</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="john@empresa.com"
                  className="bg-zinc-900 border-none p-4 rounded-md text-white focus:ring-2 focus:ring-accent outline-none transition-all"
                />
              </div>
            </div>

            <div className="flex flex-col space-y-2">
              <label htmlFor="storeUrl" className="text-xs font-bold text-gray-500 uppercase tracking-widest">URL de tu tienda (opcional)</label>
              <input
                type="text"
                id="storeUrl"
                name="storeUrl"
                value={formData.storeUrl}
                onChange={handleChange}
                placeholder="https://tu-tienda.com"
                className="bg-zinc-900 border-none p-4 rounded-md text-white focus:ring-2 focus:ring-accent outline-none transition-all"
              />
            </div>

            <div className="flex flex-col space-y-2">
              <label htmlFor="message" className="text-xs font-bold text-gray-500 uppercase tracking-widest">¿En qué podemos ayudarte?</label>
              <textarea
                id="message"
                name="message"
                rows={4}
                required
                value={formData.message}
                onChange={handleChange}
                placeholder="Hola, necesito una auditoría UX para mi tienda..."
                className="bg-zinc-900 border-none p-4 rounded-md text-white focus:ring-2 focus:ring-accent outline-none transition-all resize-none"
              />
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className={`w-full bg-accent text-black p-5 rounded-md font-black text-xl hover:scale-[1.02] active:scale-[0.98] transition-all shadow-[0_0_30px_rgba(255,224,0,0.2)] ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
            >
              {isSubmitting ? 'ENVIANDO...' : 'ENVIAR MENSAJE'}
            </button>
          </form>
        )}
      </div>
    </section>
  );
};

export default ContactForm;

