import React, { useEffect, useState } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Services from './components/Services';
import SocialProof from './components/SocialProof';
import ContactForm from './components/ContactForm';
import Footer from './components/Footer';
import StyleGuide from './pages/StyleGuide';

function App() {
  const [currentPath, setCurrentPath] = useState(window.location.pathname);

  useEffect(() => {
    const handleLocationChange = () => {
      setCurrentPath(window.location.pathname);

      // Handle scrolling to sections if the path is something like /servicios
      const sectionId = window.location.pathname.replace('/', '');
      if (sectionId) {
        const element = document.getElementById(sectionId);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      } else {
        window.scrollTo(0, 0);
      }
    };

    window.addEventListener('popstate', handleLocationChange);
    return () => window.removeEventListener('popstate', handleLocationChange);
  }, []);

  // Simple routing logic
  const renderContent = () => {
    if (currentPath === '/guia-de-estilo') {
      return <StyleGuide />;
    }

    return (
      <main>
        <Hero />
        <Services />
        <SocialProof />
        <ContactForm />
      </main>
    );
  };

  return (
    <div className="bg-white text-[#333] selection:bg-[rgb(255,254,85)] selection:text-black min-h-screen">
      <Navbar />
      {renderContent()}
      <Footer />
    </div>
  );
}

export default App;

